 3→/**
 4→ * Call MCP Tool via HTTP
 5→ *
 6→ * Helper script to call MCP tools on the deployed Fly.io server
 7→ *
 8→ * Usage:
 9→ *   npx tsx call-mcp-tool.ts <tool-name> <params-json>
10→ */
11→
12→const MCP_SERVER_URL = 'https://mittwald-mcp-fly2.fly.dev/mcp';
13→
14→interface MCPRequest {
15→  jsonrpc: '2.0';
16→  id: number;
17→  method: string;
18→  params: {
19→    name: string;
20→    arguments?: Record<string, any>;
21→  };
22→}
23→
24→interface MCPResponse {
25→  jsonrpc: '2.0';
26→  id: number;
27→  result?: any;
28→  error?: {
29→    code: number;
30→    message: string;
31→    data?: any;
32→  };
33→}
34→
35→async function callMCPTool(toolName: string, params: Record<string, any> = {}): Promise<any> {
36→  const request: MCPRequest = {
37→    jsonrpc: '2.0',
38→    id: Date.now(),
39→    method: 'tools/call',
40→    params: {
41→      name: toolName,
42→      arguments: params,
43→    },
44→  };
45→
46→  console.error(`Calling tool: ${toolName}`);
47→  console.error(`Parameters:`, JSON.stringify(params, null, 2));
48→
49→  const response = await fetch(MCP_SERVER_URL, {
50→    method: 'POST',
51→    headers: {
52→      'Content-Type': 'application/json',
53→    },
54→    body: JSON.stringify(request),
55→  });
56→
57→  if (!response.ok) {
58→    throw new Error(`HTTP error: ${response.status} ${response.statusText}`);
59→  }
60→
61→  const data: MCPResponse = await response.json();
62→
63→  if (data.error) {
64→    throw new Error(`MCP error: ${data.error.message}`);
65→  }
66→
67→  return data.result;
68→}
69→
70→async function main() {
71→  const args = process.argv.slice(2);
72→
73→  if (args.length < 1) {
74→    console.error('Usage: call-mcp-tool.ts <tool-name> [params-json]');
75→    process.exit(1);
76→  }
77→
78→  const toolName = args[0];
79→  const params = args[1] ? JSON.parse(args[1]) : {};
80→
81→  try {
82→    const result = await callMCPTool(toolName, params);
83→    console.log(JSON.stringify(result, null, 2));
84→  } catch (error) {
85→    console.error('Error:', error);
86→    process.exit(1);
87→  }
88→}
89→
