 31→function base64UrlEncode(input: Buffer | Uint8Array | string): string {
 32→  const buffer = typeof input === 'string' ? Buffer.from(input) : Buffer.from(input);
 33→  return buffer
 34→    .toString('base64')
 35→    .replace(/\+/g, '-')
 36→    .replace(/\//g, '_')
 37→    .replace(/=+$/, '');
 38→}
 39→
 40→function generatePkcePair(): { codeVerifier: string; codeChallenge: string } {
 41→  const codeVerifier = base64UrlEncode(randomBytes(32));
 42→  const codeChallenge = base64UrlEncode(createHash('sha256').update(codeVerifier).digest());
 43→  return { codeVerifier, codeChallenge };
 44→}
