 62→async function readFirstJsonMessage(stream: ReadableStream<Uint8Array>): Promise<any> {
 63→  const reader = stream.getReader();
 64→  let buffer = '';
 65→  let dataLines: string[] = [];
 66→  try {
 67→    while (true) {
 68→      const { value, done } = await reader.read();
 69→      if (done) {
 70→        const remaining = buffer.trim();
 71→        if (remaining) {
 72→          dataLines.push(remaining);
 73→        }
 74→        if (dataLines.length > 0) {
 75→          return JSON.parse(dataLines.join('\n'));
 76→        }
 77→        throw new Error('MCP stream ended without message');
 78→      }
 79→      buffer += Buffer.from(value).toString('utf-8');
 80→      let newlineIndex;
 81→      while ((newlineIndex = buffer.indexOf('\n')) !== -1) {
 82→        const line = buffer.slice(0, newlineIndex).trim();
 83→        buffer = buffer.slice(newlineIndex + 1);
 84→        if (!line) {
 85→          if (dataLines.length > 0) {
 86→            return JSON.parse(dataLines.join('\n'));
 87→          }
 88→          continue;
 89→        }
 90→        if (line.startsWith('data:')) {
 91→          dataLines.push(line.slice(5).trim());
 92→          continue;
 93→        }
 94→        if (line.startsWith('event:')) {
 95→          continue;
 96→        }
 97→        if (line.startsWith(':')) {
 98→          continue;
 99→        }
100→        // Fallback for raw JSON lines
101→        if (line) {
102→          return JSON.parse(line);
103→        }
104→      }
105→    }
106→  } finally {
107→    await reader.cancel().catch(() => {});
108→  }
109→}
