118→async function postMcpStreamRequest({ baseUrl, token, payload, sessionId }: McpRequestOptions) {
119→  const response = await fetch(`${baseUrl}/mcp`, {
120→    method: 'POST',
121→    headers: {
122→      Authorization: `Bearer ${token}`,
123→      'Content-Type': 'application/json',
124→      Accept: 'application/json, text/event-stream',
125→      'mcp-protocol-version': '2025-06-18',
126→      ...(sessionId ? { 'mcp-session-id': sessionId } : {})
127→    },
128→    body: JSON.stringify(payload)
129→  });
130→
131→  if (!response.body) {
132→    throw new Error('MCP response stream missing');
133→  }
134→
135→  const message = await readFirstJsonMessage(response.body);
136→  return { response, message };
137→}
