 270→function parseArgs(argv: string[]): RunnerOptions {
 271→  const mcpConfigDefault = toAbsolute('.mcp.json');
 272→  let mcpUrlExplicitlySet = false;
 273→
 274→  const options: RunnerOptions = {
 275→    agents: ['claude'],
 276→    promptDir: toAbsolute('evals/prompts'),
 277→    outputDir: toAbsolute('evals/results/agent-e2e'),
 278→    timeoutMs: DEFAULT_TIMEOUT_MS,
 279→    mcpConfigPath: mcpConfigDefault,
