 429→
 430→  function walk(current: string): void {
 431→    const entries = fs.readdirSync(current, { withFileTypes: true });
 432→    for (const entry of entries) {
 433→      const absolute = path.join(current, entry.name);
 434→      if (entry.isDirectory()) {
 435→        walk(absolute);
 436→        continue;
 437→      }
 438→      if (entry.isFile() && entry.name.endsWith('.json')) {
 439→        out.push(absolute);
 440→      }
 441→    }
 442→  }
 443→
 444→  walk(rootDir);
 445→  return out.sort();
 446→}
 447→
 448→function loadPromptCases(
 449→  options: RunnerOptions
 450→): { cases: PromptCase[]; invalidFiles: InvalidPromptFile[] } {
 451→  if (!fs.existsSync(options.promptDir)) {
 452→    throw new Error(`Prompt directory not found: ${options.promptDir}`);
 453→  }
 454→
 455→  const files = walkJsonFiles(options.promptDir).filter(
 456→    (filePath) => path.basename(filePath) !== 'generation-manifest.json'
 457→  );
 458→
 459→  const invalidFiles: InvalidPromptFile[] = [];
 460→  const cases: PromptCase[] = [];
 461→
 462→  for (const filePath of files) {
 463→    let parsed: any;
 464→    try {
 465→      parsed = JSON.parse(fs.readFileSync(filePath, 'utf-8'));
 466→    } catch (error) {
 467→      invalidFiles.push({
 468→        filePath,
 469→        error: error instanceof Error ? error.message : String(error),
 470→      });
 471→      continue;
 472→    }
 473→
 474→    const prompt = parsed?.input?.prompt;
 475→    const toolName = parsed?.input?.tool_name;
 476→    if (typeof prompt !== 'string' || typeof toolName !== 'string') {
 477→      continue;
 478→    }
 479→
 480→    const domain =
 481→      typeof parsed?.metadata?.domain === 'string'
 482→        ? parsed.metadata.domain
 483→        : path.basename(path.dirname(filePath));
 484→
 485→    if (options.domains && !options.domains.has(domain)) {
 486→      continue;
 487→    }
 488→
 489→    if (options.tools && !options.tools.has(normalizeToolName(toolName))) {
 490→      continue;
 491→    }
 492→
 493→    const fileBase = path.basename(filePath, '.json');
 494→    const displayName =
 495→      typeof parsed?.input?.display_name === 'string'
 496→        ? parsed.input.display_name
 497→        : fileBase;
 498→
 499→    cases.push({
 500→      id: fileBase,
 501→      domain,
 502→      promptFile: filePath,
 503→      toolName,
 504→      displayName,
 505→      prompt,
 506→    });
 507→  }
 508→
 509→  if (options.maxTools !== undefined) {
 510→    return {
 511→      cases: cases.slice(0, options.maxTools),
 512→      invalidFiles,
 513→    };
 514→  }
 515→
 516→  return { cases, invalidFiles };
 517→}
 518→
 519→function createLineParser(onLine: (line: string) => void): {
 520→  push: (chunk: string) => void;
 521→  flush: () => void;
 522→} {
 523→  let buffer = '';
 524→
 525→  return {
 526→    push(chunk: string) {
 527→      buffer += chunk;
 528→      const lines = buffer.split(/\r?\n/);
 529→      buffer = lines.pop() ?? '';
 530→      for (const line of lines) {
 531→        if (line.length > 0) {
 532→          onLine(line);
 533→        }
 534→      }
 535→    },
 536→    flush() {
 537→      if (buffer.length > 0) {
 538→        onLine(buffer);
 539→      }
 540→      buffer = '';
 541→    },
 542→  };
 543→}
 544→
 545→function parseClaudeEvent(
 546→  parsed: any,
 547→  toolsCalled: string[],
 548→  messages: string[],
 549→  toolCallErrors: string[],
 550→  mcpServerStatus: Record<string, string>
 551→): void {
 552→  if (parsed?.type === 'system' && parsed?.subtype === 'init') {
 553→    if (Array.isArray(parsed?.mcp_servers)) {
 554→      for (const server of parsed.mcp_servers) {
 555→        if (
 556→          typeof server?.name === 'string' &&
 557→          typeof server?.status === 'string'
 558→        ) {
 559→          mcpServerStatus[server.name] = server.status;
 560→        }
 561→      }
 562→    }
 563→    return;
 564→  }
 565→
 566→  if (parsed?.type === 'assistant' && parsed?.message?.content) {
 567→    const content = parsed.message.content;
 568→    if (Array.isArray(content)) {
 569→      for (const item of content) {
 570→        if (item?.type === 'tool_use' && typeof item?.name === 'string') {
 571→          toolsCalled.push(item.name);
 572→        }
 573→        if (item?.type === 'text' && typeof item?.text === 'string') {
 574→          messages.push(item.text);
 575→        }
 576→      }
 577→    }
 578→    return;
 579→  }
 580→
 581→  if (parsed?.type === 'result' && parsed?.is_error === true) {
 582→    toolCallErrors.push(
 583→      typeof parsed?.result === 'string'
 584→        ? parsed.result
 585→        : JSON.stringify(parsed?.result ?? parsed)
 586→    );
 587→  }
 588→}
 589→
 590→function parseCodexEvent(
 591→  parsed: any,
 592→  toolsCalled: string[],
 593→  messages: string[],
 594→  toolCallErrors: string[]
 595→): void {
 596→  if (parsed?.type === 'item.started' || parsed?.type === 'item.completed') {
 597→    const item = parsed?.item;
 598→    if (!item || typeof item !== 'object') {
 599→      return;
 600→    }
 601→
 602→    if (item.type === 'mcp_tool_call') {
 603→      if (typeof item.tool === 'string') {
 604→        toolsCalled.push(item.tool);
 605→      }
 606→      if (item.error) {
 607→        toolCallErrors.push(
 608→          typeof item.error === 'string' ? item.error : JSON.stringify(item.error)
 609→        );
 610→      }
 611→      if (item.status === 'failed') {
 612→        toolCallErrors.push(
 613→          `MCP tool call failed: ${typeof item.tool === 'string' ? item.tool : 'unknown_tool'}`
 614→        );
 615→      }
 616→      return;
 617→    }
 618→
 619→    if (item.type === 'agent_message' && typeof item.text === 'string') {
 620→      messages.push(item.text);
 621→      return;
 622→    }
 623→  }
 624→
 625→  if (parsed?.type === 'error') {
 626→    toolCallErrors.push(
 627→      typeof parsed?.message === 'string'
 628→        ? parsed.message
 629→        : JSON.stringify(parsed)
 630→    );
 631→  }
 632→}
 633→
 634→function parseOpencodeEvent(
 635→  parsed: any,
 636→  toolsCalled: string[],
 637→  messages: string[],
 638→  toolCallErrors: string[]
 639→): void {
 640→  if (parsed?.type === 'tool_use' && parsed?.part?.type === 'tool') {
 641→    if (typeof parsed?.part?.tool === 'string') {
 642→      toolsCalled.push(parsed.part.tool);
 643→    }
 644→    const status = parsed?.part?.state?.status;
 645→    if (status === 'error' || status === 'failed') {
 646→      toolCallErrors.push(
 647→        `Tool ${String(parsed?.part?.tool ?? 'unknown')} failed in opencode`
 648→      );
 649→    }
 650→    return;
 651→  }
 652→
 653→  if (parsed?.type === 'text' && typeof parsed?.part?.text === 'string') {
 654→    messages.push(parsed.part.text);
 655→    return;
 656→  }
 657→
 658→  if (parsed?.type === 'error') {
 659→    toolCallErrors.push(
 660→      typeof parsed?.error?.message === 'string'
 661→        ? parsed.error.message
 662→        : JSON.stringify(parsed?.error ?? parsed)
 663→    );
 664→  }
 665→}
 666→
 667→function dedupePreserveOrder(values: string[]): string[] {
 668→  const seen = new Set<string>();
 669→  const out: string[] = [];
 670→  for (const value of values) {
 671→    if (seen.has(value)) continue;
 672→    seen.add(value);
 673→    out.push(value);
 674→  }
 675→  return out;
 676→}
 677→
 678→function buildAgentCommand(
 679→  agent: AgentName,
 680→  prompt: string,
 681→  options: RunnerOptions
 682→): { command: string; args: string[] } {
 683→  if (agent === 'claude') {
 684→    const args = [
 685→      '--print',
 686→      prompt,
 687→      '--output-format',
 688→      'stream-json',
 689→      '--verbose',
 690→      '--allowedTools',
 691→      'mcp__mittwald__*',
 692→      '--mcp-config',
 693→      options.mcpConfigPath,
 694→      '--strict-mcp-config',
 695→    ];
 696→    if (options.claudeModel) {
 697→      args.push('--model', options.claudeModel);
 698→    }
 699→    return { command: 'claude', args };
 700→  }
 701→
 702→  if (agent === 'codex') {
 703→    const args = ['exec', '--json', prompt];
 704→    if (options.codexModel) {
 705→      args.push('--model', options.codexModel);
 706→    }
 707→
 708→    args.push(
 709→      '-c',
 710→      `mcp_servers.${options.codexMcpServerName}.url="${options.mcpUrl}"`
 711→    );
 712→    for (const serverName of CODEX_MCP_SERVERS_TO_DISABLE) {
 713→      if (serverName === options.codexMcpServerName) continue;
 714→      args.push('-c', `mcp_servers.${serverName}.enabled=false`);
 715→    }
 716→
 717→    return { command: 'codex', args };
 718→  }
 719→
 720→  const args = ['run', prompt, '--format', 'json'];
 721→  if (options.opencodeModel) {
 722→    args.push('--model', options.opencodeModel);
 723→  }
 724→  return { command: 'opencode', args };
 725→}
 726→
 727→async function executePromptWithAgent(
 728→  agent: AgentName,
 729→  prompt: string,
 730→  options: RunnerOptions
 731→): Promise<AgentExecutionResult> {
 732→  const { command, args } = buildAgentCommand(agent, prompt, options);
 733→  const started = Date.now();
 734→
 735→  return await new Promise<AgentExecutionResult>((resolve) => {
 736→    const toolsCalled: string[] = [];
 737→    const messages: string[] = [];
 738→    const toolCallErrors: string[] = [];
 739→    const mcpServerStatus: Record<string, string> = {};
 740→    let stdout = '';
 741→    let stderr = '';
 742→    let parseErrors = 0;
 743→    let timedOut = false;
 744→
 745→    const child = spawn(command, args, {
 746→      cwd: process.cwd(),
 747→      stdio: ['ignore', 'pipe', 'pipe'],
 748→      env: {
 749→        ...process.env,
 750→      },
 751→    });
 752→
 753→    const stdoutParser = createLineParser((line) => {
 754→      let parsed: any;
 755→      try {
 756→        parsed = JSON.parse(line);
 757→      } catch {
 758→        parseErrors += 1;
 759→        return;
 760→      }
 761→
 762→      if (agent === 'claude') {
 763→        parseClaudeEvent(
 764→          parsed,
 765→          toolsCalled,
 766→          messages,
 767→          toolCallErrors,
 768→          mcpServerStatus
 769→        );
 770→      } else if (agent === 'codex') {
 771→        parseCodexEvent(parsed, toolsCalled, messages, toolCallErrors);
 772→      } else {
 773→        parseOpencodeEvent(parsed, toolsCalled, messages, toolCallErrors);
 774→      }
 775→    });
 776→
 777→    child.stdout.on('data', (chunk: Buffer) => {
 778→      const text = chunk.toString();
 779→      stdout += text;
 780→      stdoutParser.push(text);
 781→    });
 782→
 783→    child.stderr.on('data', (chunk: Buffer) => {
 784→      stderr += chunk.toString();
 785→    });
 786→
 787→    const timeout = setTimeout(() => {
 788→      timedOut = true;
 789→      child.kill('SIGTERM');
 790→      setTimeout(() => {
 791→        if (!child.killed) {
 792→          child.kill('SIGKILL');
 793→        }
 794→      }, 3000);
 795→    }, options.timeoutMs);
 796→
 797→    child.on('error', (error) => {
 798→      clearTimeout(timeout);
 799→      resolve({
 800→        agent,
 801→        command,
 802→        args,
 803→        exitCode: 127,
 804→        durationMs: Date.now() - started,
 805→        timedOut: false,
 806→        stdout,
 807→        stderr: `${stderr}\n${error.message}`.trim(),
 808→        toolsCalled: dedupePreserveOrder(toolsCalled),
 809→        toolCallErrors: dedupePreserveOrder(toolCallErrors),
 810→        messages,
 811→        parseErrors,
 812→        mcpServerStatus,
 813→      });
 814→    });
 815→
 816→    child.on('close', (exitCode) => {
 817→      clearTimeout(timeout);
 818→      stdoutParser.flush();
 819→
 820→      resolve({
 821→        agent,
 822→        command,
 823→        args,
 824→        exitCode,
 825→        durationMs: Date.now() - started,
 826→        timedOut,
 827→        stdout,
 828→        stderr,
 829→        toolsCalled: dedupePreserveOrder(toolsCalled),
 830→        toolCallErrors: dedupePreserveOrder(toolCallErrors),
 831→        messages,
 832→        parseErrors,
 833→        mcpServerStatus,
 834→      });
 835→    });
 836→  });
 837→}
