 843→): Promise<{ exitCode: number | null; stdout: string; stderr: string; timedOut: boolean }> {
 844→  return await new Promise((resolve) => {
 845→    let stdout = '';
 846→    let stderr = '';
 847→    let timedOut = false;
 848→
 849→    const child = spawn(command, args, {
 850→      cwd: process.cwd(),
 851→      stdio: ['ignore', 'pipe', 'pipe'],
 852→      env: {
 853→        ...process.env,
 854→      },
 855→    });
 856→
 857→    child.stdout.on('data', (chunk: Buffer) => {
 858→      stdout += chunk.toString();
 859→    });
 860→
 861→    child.stderr.on('data', (chunk: Buffer) => {
 862→      stderr += chunk.toString();
 863→    });
 864→
 865→    const timeout = setTimeout(() => {
 866→      timedOut = true;
 867→      child.kill('SIGTERM');
 868→      setTimeout(() => {
 869→        if (!child.killed) {
 870→          child.kill('SIGKILL');
 871→        }
