1013→function extractSelfAssessment(rawText: string): AssessmentParseResult {
1014→  const startIndex = rawText.indexOf(SELF_ASSESSMENT_START);
1015→  const endIndex = rawText.indexOf(SELF_ASSESSMENT_END);
1016→
1017→  if (startIndex < 0 || endIndex < 0 || endIndex <= startIndex) {
1018→    return { error: 'Self-assessment markers not found' };
1019→  }
1020→
1021→  let payload = rawText
1022→    .slice(startIndex + SELF_ASSESSMENT_START.length, endIndex)
1023→    .trim();
1024→
1025→  if (payload.startsWith('```json')) {
1026→    payload = payload.replace(/^```json\s*/i, '').replace(/\s*```$/, '');
1027→  } else if (payload.startsWith('```')) {
1028→    payload = payload.replace(/^```\s*/, '').replace(/\s*```$/, '');
1029→  }
1030→
1031→  try {
1032→    const parsed = JSON.parse(payload) as SelfAssessment;
1033→    if (typeof parsed.success !== 'boolean') {
1034→      return { error: 'Self-assessment JSON missing boolean success field', rawJson: payload };
1035→    }
1036→    return { assessment: parsed, rawJson: payload };
1037→  } catch (error) {
1038→    return {
1039→      error: `Failed to parse self-assessment JSON: ${
1040→        error instanceof Error ? error.message : String(error)
1041→      }`,
1042→      rawJson: payload,
1043→    };
1044→  }
1045→}
1046→
1047→function buildCaseRawText(execution: AgentExecutionResult): string {
1048→  return `${execution.stdout}\n${execution.messages.join('\n')}`;
1049→}
1050→
1051→function evaluateCase(
1052→  promptCase: PromptCase,
1053→  execution: AgentExecutionResult,
1054→  options: RunnerOptions
1055→): {
1056→  status: 'success' | 'failure';
1057→  failureCategory?: FailureCategory;
1058→  failureReason?: string;
1059→  expectedToolCalled: boolean;
1060→  selfAssessment?: SelfAssessment;
1061→} {
1062→  const expectedTool = normalizeToolName(promptCase.toolName);
1063→  const calledToolsNormalized = new Set(
1064→    execution.toolsCalled.map((tool) => normalizeToolName(tool))
1065→  );
1066→  const expectedToolCalled = calledToolsNormalized.has(expectedTool);
1067→
1068→  if (execution.timedOut) {
1069→    return {
1070→      status: 'failure',
1071→      failureCategory: 'timeout',
1072→      failureReason: `Agent timed out after ${execution.durationMs}ms`,
1073→      expectedToolCalled,
1074→    };
1075→  }
1076→
1077→  if (execution.exitCode !== 0) {
1078→    return {
1079→      status: 'failure',
1080→      failureCategory: 'agent_exit_nonzero',
1081→      failureReason: `Agent exited with code ${execution.exitCode}. stderr: ${execution.stderr.slice(0, 500)}`,
1082→      expectedToolCalled,
1083→    };
1084→  }
1085→
1086→  if (!expectedToolCalled) {
1087→    return {
1088→      status: 'failure',
1089→      failureCategory: 'missing_expected_tool_call',
1090→      failureReason: `Expected tool ${promptCase.toolName} was not called`,
1091→      expectedToolCalled,
1092→    };
1093→  }
1094→
1095→  if (execution.toolCallErrors.length > 0) {
1096→    return {
1097→      status: 'failure',
1098→      failureCategory: 'tool_call_error',
1099→      failureReason: execution.toolCallErrors.join('; '),
1100→      expectedToolCalled,
1101→    };
1102→  }
1103→
1104→  const assessmentResult = extractSelfAssessment(buildCaseRawText(execution));
1105→  if (!assessmentResult.assessment) {
1106→    if (!options.requireSelfAssessment) {
1107→      return {
1108→        status: 'success',
1109→        expectedToolCalled,
1110→      };
1111→    }
1112→    return {
1113→      status: 'failure',
1114→      failureCategory: assessmentResult.rawJson
1115→        ? 'invalid_self_assessment'
1116→        : 'missing_self_assessment',
1117→      failureReason: assessmentResult.error,
1118→      expectedToolCalled,
1119→    };
1120→  }
1121→
1122→  if (
1123→    options.requireSelfAssessment &&
1124→    assessmentResult.assessment.tool_executed &&
1125→    normalizeToolName(assessmentResult.assessment.tool_executed) !==
1126→      normalizeToolName(promptCase.toolName)
1127→  ) {
1128→    return {
1129→      status: 'failure',
1130→      failureCategory: 'tool_mismatch_in_self_assessment',
1131→      failureReason: `Self-assessment tool_executed '${assessmentResult.assessment.tool_executed}' does not match expected '${promptCase.toolName}'`,
1132→      expectedToolCalled,
1133→      selfAssessment: assessmentResult.assessment,
1134→    };
1135→  }
1136→
1137→  if (options.requireSelfAssessment && assessmentResult.assessment.success !== true) {
1138→    return {
1139→      status: 'failure',
1140→      failureCategory: 'self_assessment_reported_failure',
1141→      failureReason:
1142→        typeof assessmentResult.assessment.execution_notes === 'string'
1143→          ? assessmentResult.assessment.execution_notes
1144→          : 'Self-assessment reported failure',
1145→      expectedToolCalled,
1146→      selfAssessment: assessmentResult.assessment,
1147→    };
1148→  }
1149→
1150→  return {
1151→    status: 'success',
1152→    expectedToolCalled,
1153→    selfAssessment: assessmentResult.assessment,
1154→  };
1155→}
