1259→function formatPercent(value: number): number {
1260→  return Number(value.toFixed(2));
1261→}
1262→
1263→function generateSummary(
1264→  runId: string,
1265→  runDir: string,
1266→  options: RunnerOptions,
1267→  cleanupProjectPrefix: string,
1268→  promptCases: PromptCase[],
1269→  invalidFiles: InvalidPromptFile[],
1270→  preflight: AgentPreflightResult[],
1271→  results: ToolCaseResult[],
1272→  cleanup?: ProjectCleanupResult
1273→): RunSummary {
1274→  const totalCaseRuns = results.length;
1275→  const passedCaseRuns = results.filter((r) => r.status === 'success').length;
1276→  const failedCaseRuns = totalCaseRuns - passedCaseRuns;
1277→  const matrixCoveragePercent =
1278→    totalCaseRuns > 0 ? formatPercent((passedCaseRuns / totalCaseRuns) * 100) : 0;
1279→
1280→  const perAgent = Object.fromEntries(
1281→    options.agents.map((agent) => {
1282→      const scoped = results.filter((result) => result.agent === agent);
1283→      const passed = scoped.filter((result) => result.status === 'success').length;
1284→      const failed = scoped.length - passed;
1285→      const coveragePercent =
1286→        scoped.length > 0 ? formatPercent((passed / scoped.length) * 100) : 0;
1287→      return [agent, { total: scoped.length, passed, failed, coveragePercent }];
1288→    })
1289→  ) as RunSummary['perAgent'];
1290→
1291→  const toolMap = new Map<
1292→    string,
1293→    {
1294→      toolName: string;
1295→      domain: string;
1296→      displayName: string;
1297→      byAgent: Record<AgentName, 'success' | 'failure' | 'not_run'>;
1298→    }
1299→  >();
1300→
1301→  for (const promptCase of promptCases) {
1302→    if (toolMap.has(promptCase.toolName)) continue;
1303→    toolMap.set(promptCase.toolName, {
1304→      toolName: promptCase.toolName,
1305→      domain: promptCase.domain,
1306→      displayName: promptCase.displayName,
1307→      byAgent: Object.fromEntries(
1308→        SUPPORTED_AGENTS.map((agent) => [agent, 'not_run'])
1309→      ) as Record<AgentName, 'success' | 'failure' | 'not_run'>,
1310→    });
1311→  }
1312→
1313→  for (const result of results) {
1314→    const entry = toolMap.get(result.toolName);
1315→    if (!entry) continue;
1316→    entry.byAgent[result.agent] =
1317→      result.status === 'success' ? 'success' : 'failure';
1318→  }
1319→
1320→  const perTool = Array.from(toolMap.values()).map((entry) => {
1321→    const statuses = options.agents.map((agent) => entry.byAgent[agent]);
1322→    const covered =
1323→      options.coverageMode === 'all-agents'
1324→        ? statuses.every((status) => status === 'success')
1325→        : statuses.some((status) => status === 'success');
1326→    return { ...entry, covered };
1327→  });
1328→
1329→  const totalTools = perTool.length;
1330→  const coveredTools = perTool.filter((tool) => tool.covered).length;
1331→  const toolCoveragePercent =
1332→    totalTools > 0 ? formatPercent((coveredTools / totalTools) * 100) : 0;
1333→
1334→  const reasons: string[] = [];
1335→  if (invalidFiles.length > 0) {
1336→    reasons.push(`${invalidFiles.length} malformed prompt file(s)`);
1337→  }
1338→  const failedPreflight = preflight.filter((p) => !p.ok);
1339→  if (failedPreflight.length > 0) {
1340→    reasons.push(
1341→      `Preflight failed for: ${failedPreflight.map((item) => item.agent).join(', ')}`
1342→    );
1343→  }
1344→  if (toolCoveragePercent < options.requireCoverage) {
1345→    reasons.push(
1346→      `Tool coverage ${toolCoveragePercent}% is below required ${options.requireCoverage}%`
1347→    );
1348→  }
1349→  if (cleanup) {
1350→    if (cleanup.listError) {
1351→      reasons.push(`Cleanup failed to list projects: ${cleanup.listError}`);
1352→    }
1353→    if (cleanup.failed.length > 0) {
1354→      reasons.push(
1355→        `Cleanup failed for ${cleanup.failed.length} test project(s): ${cleanup.failed
1356→          .map((item) => item.id)
1357→          .join(', ')}`
1358→      );
1359→    }
1360→  }
1361→
1362→  return {
1363→    runId,
1364→    generatedAt: new Date().toISOString(),
1365→    outputDir: runDir,
1366→    options: {
1367→      agents: options.agents,
1368→      promptDir: options.promptDir,
1369→      timeoutMs: options.timeoutMs,
1370→      target: options.target,
1371→      requireCoverage: options.requireCoverage,
1372→      coverageMode: options.coverageMode,
1373→      requireSelfAssessment: options.requireSelfAssessment,
1374→      cleanupTestProjects: options.cleanupTestProjects,
1375→      cleanupProjectPrefix,
1376→      mcpUrl: options.mcpUrl,
1377→      mcpConfigPath: options.mcpConfigPath,
1378→      domains: options.domains ? Array.from(options.domains) : undefined,
1379→      tools: options.tools ? Array.from(options.tools) : undefined,
1380→      maxTools: options.maxTools,
1381→    },
1382→    promptInventory: {
1383→      totalLoaded: promptCases.length,
1384→      invalidFiles,
1385→    },
1386→    preflight,
1387→    counts: {
1388→      totalCaseRuns,
1389→      passedCaseRuns,
1390→      failedCaseRuns,
1391→      matrixCoveragePercent,
1392→      totalTools,
1393→      coveredTools,
1394→      toolCoveragePercent,
1395→    },
1396→    perAgent,
1397→    perTool,
1398→    gate: {
1399→      requiredCoverage: options.requireCoverage,
1400→      mode: options.coverageMode,
1401→      passed: reasons.length === 0,
1402→      reasons,
1403→    },
1404→    cleanup,
1405→  };
1406→}
